import akka.actor.{Actor, ActorLogging, Props}

object AccountActor {
  sealed trait Command
  case class Deposit(amount: Double) extends Command
  case class Withdraw(amount: Double) extends Command
  case object GetBalance extends Command

  sealed trait Event
  case class BalanceUpdated(newBalance: Double) extends Event
  case object InsufficientFunds extends Event
  case object InvalidAmount extends Event
  case class CurrentBalance(balance: Double) extends Event

  def props(initialBalance: Double): Props = Props(new AccountActor(initialBalance))
}

class AccountActor(initialBalance: Double) extends Actor with ActorLogging {
  import AccountActor._

  private var balance: Double = initialBalance

  override def receive: Receive = {
    case Deposit(amount) =>
      if (amount > 0) {
        balance += amount
        sender() ! BalanceUpdated(balance)
        log.info(s"Deposited $amount. New balance: $balance")
      } else {
        sender() ! InvalidAmount
        log.warning(s"Attempted to deposit invalid amount: $amount")
      }

    case Withdraw(amount) =>
      if (amount > 0) {
        if (balance >= amount) {
          balance -= amount
          sender() ! BalanceUpdated(balance)
          log.info(s"Withdrew $amount. New balance: $balance")
        } else {
          sender() ! InsufficientFunds
          log.warning(s"Insufficient funds for withdrawal of $amount. Current balance: $balance")
        }
      } else {
        sender() ! InvalidAmount
        log.warning(s"Attempted to withdraw invalid amount: $amount")
      }

    case GetBalance =>
      sender() ! CurrentBalance(balance)
      log.debug(s"Current balance requested: $balance")
  }
}